import React, { useState } from 'react';

// --- BRAND COLORS ---
const gold = '#D4AF37';
const terracotta = '#C04000';

// 1. THE SMALL CHOPS COMPONENT (The Default Export)
const Menu = () => {
  const [showCustomModal, setShowCustomModal] = useState(false);

  return (
    <div style={{ padding: '0 20px', marginTop: '-10px' }}>
      
      {/* THE 200K SIGNATURE PLATTER */}
      <div style={{ 
        width: '100%', backgroundColor: '#111', borderRadius: '15px', 
        marginBottom: '25px', border: `1px solid ${terracotta}44`, padding: '20px', boxSizing: 'border-box'
      }}>
        <h2 style={{ fontSize: '1.1rem', color: '#fff', margin: '0 0 8px 0', letterSpacing: '1px' }}>
          THE ÀMÍ SIGNATURE GRAND PLATTER
        </h2>
        <p style={{ fontSize: '0.75rem', color: '#888', margin: '0 0 15px 0', lineHeight: '1.5' }}>
          Handcrafted for your finest guests of 60 and above. A bespoke curation designed for elite gatherings.
        </p>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <span style={{ fontSize: '0.6rem', color: terracotta, display: 'block', fontWeight: 'bold' }}>STARTING AT</span>
            <span style={{ fontSize: '1.1rem', fontWeight: 'bold', color: gold }}>₦200,000</span>
          </div>
          <button onClick={() => setShowCustomModal(true)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', padding: '10px 20px', borderRadius: '8px', fontWeight: 'bold', fontSize: '0.7rem' }}>
            CUSTOMIZE
          </button>
        </div>
      </div>

      {/* DAILY PLATTERS */}
      <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px' }}>Daily Platters</h3>
      <div style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '12px', alignItems: 'center' }}>
        <div style={{ width: '50px', height: '50px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}></div>
        <div style={{ flex: 1 }}>
          <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>The Executive Box</h4>
          <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: gold }}>₦15,000</div>
        </div>
        <button style={{ backgroundColor: '#222', color: '#fff', border: 'none', borderRadius: '20px', padding: '6px 14px', fontSize: '0.65rem' }}>ADD</button>
      </div>

      {/* MODAL PANEL */}
      {showCustomModal && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.85)', zIndex: 1000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#161616', borderTopLeftRadius: '25px', borderTopRightRadius: '25px', padding: '30px 20px', boxSizing: 'border-box' }}>
            <h3 style={{ color: gold, margin: '0 0 10px 0' }}>Tailor Your Event</h3>
            <textarea placeholder="Flavor preferences, date, location..." style={{ width: '100%', height: '100px', backgroundColor: '#000', color: '#fff', borderRadius: '10px', padding: '10px', border: '1px solid #333' }} />
            <button onClick={() => setShowCustomModal(false)} style={{ width: '100%', marginTop: '15px', padding: '15px', backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '10px', fontWeight: 'bold' }}>REQUEST QUOTE</button>
          </div>
        </div>
      )}
    </div>
  );
};

// 2. THE LUNCH COMPONENT (The Named Export)
// Adding this here stops the "Lunch not found" error!
export const Lunch = () => {
  const meals = [
    { name: "The Heritage Jollof Plate", price: "4,500", side: "Grilled Chicken & Plantain" },
    { name: "Executive Swallows", price: "5,500", side: "Poundo Yam & Choice of Soup" }
  ];

  return (
    <div style={{ padding: '0 20px' }}>
      <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px' }}>Corporate Lunch</h3>
      {meals.map((meal) => (
        <div key={meal.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '15px', alignItems: 'center', borderLeft: `3px solid ${terracotta}` }}>
          <div style={{ flex: 1 }}>
            <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>{meal.name}</h4>
            <p style={{ fontSize: '0.6rem', color: '#666', margin: '3px 0' }}>{meal.side}</p>
            <div style={{ fontSize: '0.95rem', fontWeight: 'bold', color: gold }}>₦{meal.price}</div>
          </div>
          <button style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '20px', padding: '6px 14px', fontSize: '0.65rem' }}>ADD</button>
        </div>
      ))}
    </div>
  );
};

export default Menu;
